from typing_extensions import Literal, TypedDict
from typing import Any, List, Dict, Optional, Union, Tuple
from typing import Any, List, Dict, Optional
import logging
import asyncio
class BaseReporter(object):
    """Delegate class to provider progress reporting for the resolver."""

    def starting(self) -> Any:
        """Called before the resolution actually starts."""

    def starting_round(self, index) -> Any:
        """Called before each round of resolution starts.

        The index is zero-based.
        """

    def ending_round(self, index, state) -> Any:
        """Called before each round of resolution ends.

        This is NOT called if the resolution ends at this round. Use `ending`
        if you want to report finalization. The index is zero-based.
        """

    def ending(self, state) -> Any:
        """Called before the resolution ends successfully."""

    def adding_requirement(self, requirement, parent) -> Any:
        """Called when adding a new requirement into the resolve criteria.

        :param requirement: The additional requirement to be applied to filter
            the available candidaites.
        :param parent: The candidate that requires ``requirement`` as a
            dependency, or None if ``requirement`` is one of the root
            requirements passed in from ``Resolver.resolve()``.
        """

    def resolving_conflicts(self, causes) -> Any:
        """Called when starting to attempt requirement conflict resolution.

        :param causes: The information on the collision that caused the backtracking.
        """

    def rejecting_candidate(self, criterion, candidate) -> Any:
        """Called when rejecting a candidate during backtracking."""

    def pinning(self, candidate) -> Any:
        """Called when adding a candidate to the potential solution."""
